## React Component Implementation

```tsx
// src/components/Logo/WbotyLogo.tsx
import styles from './WbotyLogo.module.css';

interface WbotyLogoProps {
  size?: 'small' | 'medium' | 'large';
  variant?: 'auto' | 'light' | 'dark';
  className?: string;
}

export default function WbotyLogo({ 
  size = 'medium', 
  variant = 'auto',
  className = '' 
}: WbotyLogoProps) {
  const sizeClass = {
    small: styles.logoSmall,
    medium: styles.logoMedium,
    large: styles.logoLarge
  }[size];

  const variantClass = {
    auto: styles.logoAuto,
    light: styles.logoLight,
    dark: styles.logoDark
  }[variant];

  return (
    <div className={`${styles.logo} ${sizeClass} ${variantClass} ${className}`}>
      <svg viewBox="0 0 120 120" fill="none" xmlns="http://www.w3.org/2000/svg">
        {/* SVG paths as above, using CSS variables */}
        <path 
          d="M90 30H30C25.5817 30 22 33.5817 22 38V82C22 86.4183 25.5817 90 30 90H70L90 110V90C94.4183 90 98 86.4183 98 82V38C98 33.5817 94.4183 30 90 30Z"
          stroke="var(--logo-bubble-color)"
          strokeWidth="3"
        />
        {/* ... rest of SVG with CSS variable references */}
      </svg>
    </div>
  );
}
```

